// Appraise every fresh listing with the public API and let only the
// bargains through: asking price below 85% of the model's estimate.
// A one-off appraisal gets consulted once; a bargain feed gets paid
// for monthly -- this node is the product.
const UMBRAL = 0.85;
const API = 'https://tasador-sd.vercel.app/v1/appraisals';

const gangas = [];
for (const item of $input.all()) {
  const l = item.json;
  if (!l.sector) continue; // empty placeholder item
  let r;
  try {
    r = await this.helpers.httpRequest({
      method: 'POST',
      url: API,
      body: {
        sector: l.sector,
        area_m2: Number(l.area_m2),
        bedrooms: Number(l.bedrooms),
        bathrooms: Number(l.bathrooms),
        parking_spots: Number(l.parking_spots),
        furnished: l.furnished ? 1 : 0,
        age_years: Number(l.age_years),
      },
      json: true,
    });
  } catch (error) {
    continue; // 422 = outside the model's reliable range, not alertable
  }
  if (!r.estimate || Number(l.price_dop) >= r.estimate * UMBRAL) continue;
  gangas.push({
    json: {
      ...l,
      estimate: Math.round(r.estimate),
      descuento_pct: Math.round((1 - Number(l.price_dop) / r.estimate) * 100),
    },
  });
}
return gangas;

